import React, { useEffect, useState } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import toast from 'react-hot-toast';
import doctorService from '../../services/doctorService';
import DoctorStatusBadge from '../../components/doctors/DoctorStatusBadge';

const DAYS = { MON:'Monday',TUE:'Tuesday',WED:'Wednesday',THU:'Thursday',FRI:'Friday',SAT:'Saturday',SUN:'Sunday' };

function DoctorDetailPage() {
  const { id }    = useParams();
  const navigate  = useNavigate();
  const [doctor, setDoctor] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    doctorService.getDoctor(id)
      .then(data => setDoctor(data.data))
      .catch(() => { toast.error('Doctor not found.'); navigate('/doctors'); })
      .finally(() => setLoading(false));
  }, [id]);

  if (loading) return (
    <div className="flex items-center justify-center py-24">
      <svg className="animate-spin w-8 h-8 text-teal-500" fill="none" viewBox="0 0 24 24">
        <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"/>
        <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4z"/>
      </svg>
    </div>
  );

  if (!doctor) return null;

  const initials = doctor.full_name?.split(' ').map(n => n[0]).join('').toUpperCase().slice(0,2);

  return (
    <div className="max-w-2xl mx-auto space-y-4">
      <button onClick={() => navigate(-1)}
        className="flex items-center gap-1.5 text-xs text-gray-500 hover:text-teal-600">
        ← Back
      </button>

      {/* Hero */}
      <div className="bg-gradient-to-r from-teal-700 to-teal-900 rounded-xl p-6 text-white">
        <div className="flex items-center gap-4">
          <div className="w-16 h-16 rounded-full bg-white/20 flex items-center justify-center
                          text-white font-bold text-xl flex-shrink-0 overflow-hidden">
            {doctor.profile_photo_url
              ? <img src={doctor.profile_photo_url} alt="photo" className="w-16 h-16 object-cover"/>
              : initials}
          </div>
          <div className="flex-1">
            <div className="flex items-center gap-2 flex-wrap">
              <h1 className="text-lg font-bold">Dr. {doctor.full_name}</h1>
              <DoctorStatusBadge status={doctor.availability_status} />
            </div>
            <p className="text-teal-200 text-xs mt-0.5">{doctor.specialization}</p>
            <p className="text-teal-100 text-xs mt-1">{doctor.qualification}</p>
          </div>
        </div>
        {doctor.bio && (
          <p className="text-teal-100 text-xs mt-4 leading-relaxed">{doctor.bio}</p>
        )}
      </div>

      {/* Info Grid */}
      <div className="grid grid-cols-2 sm:grid-cols-4 gap-3">
        {[
          { label: 'Experience',  value: `${doctor.experience_years} yrs` },
          { label: 'Consult Fee', value: `₹${Number(doctor.consultation_fee).toLocaleString()}` },
          { label: 'Rating',      value: `${Number(doctor.average_rating).toFixed(1)} ⭐` },
          { label: 'License',     value: doctor.license_number },
        ].map(item => (
          <div key={item.label} className="bg-white rounded-xl border border-gray-100 shadow-sm p-3 text-center">
            <p className="text-sm font-bold text-teal-700 truncate">{item.value}</p>
            <p className="text-xs text-gray-500 mt-0.5">{item.label}</p>
          </div>
        ))}
      </div>

      {/* Hospital */}
      {doctor.hospital_name && (
        <div className="bg-white rounded-xl border border-gray-100 shadow-sm p-4">
          <h3 className="text-xs font-semibold text-gray-700 uppercase tracking-wide mb-2">Hospital</h3>
          <p className="text-sm font-medium text-gray-900">{doctor.hospital_name}</p>
          {doctor.hospital_city && <p className="text-xs text-gray-500 mt-0.5">{doctor.hospital_city}</p>}
        </div>
      )}

      {/* Slots */}
      {doctor.slots?.length > 0 && (
        <div className="bg-white rounded-xl border border-gray-100 shadow-sm p-4">
          <h3 className="text-xs font-semibold text-gray-700 uppercase tracking-wide mb-3">
            Available Slots
          </h3>
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-2">
            {doctor.slots.filter(s => s.is_active).map(slot => (
              <div key={slot.id}
                className="flex items-center justify-between bg-teal-50 border
                           border-teal-100 rounded-lg px-3 py-2">
                <span className="text-xs font-medium text-teal-800">
                  {DAYS[slot.day] || slot.day}
                </span>
                <span className="text-xs text-teal-600">
                  {slot.start_time} – {slot.end_time}
                </span>
              </div>
            ))}
          </div>
        </div>
      )}

      {/* Book Button */}
      <div className="pb-6">
        <button
          onClick={() => navigate(`/appointments/book/${doctor.id}`)}
          className="w-full py-3 text-sm font-semibold text-white bg-teal-600
                     rounded-xl hover:bg-teal-700 transition-colors">
          📅 Book Appointment
        </button>
      </div>
    </div>
  );
}

export default DoctorDetailPage;
